:root {
  --bg-primary: #030508;
  --bg-secondary: #080b11;
  --bg-card: rgba(13, 18, 29, 0.45);
  --bg-card-hover: rgba(18, 25, 41, 0.65);

  --color-text-primary: #f8fafc;
  --color-text-secondary: #94a3b8;
  --color-text-muted: #64748b;

  --accent-cyan: #00f0ff;
  --accent-cyan-glow: rgba(0, 240, 255, 0.15);
  --accent-blue: #0072ff;
  --accent-blue-glow: rgba(0, 114, 255, 0.15);
  --accent-purple: #a855f7;
  --accent-purple-glow: rgba(168, 85, 247, 0.15);
  --accent-green: #10b981;
  --accent-green-glow: rgba(16, 185, 129, 0.15);
  --accent-pink: #f43f5e;

  --border-glow: rgba(255, 255, 255, 0.05);
  --border-glow-active: rgba(0, 240, 255, 0.3);

  --font-heading: 'Outfit', sans-serif;
  --font-body: 'Inter', sans-serif;
  --font-mono: 'JetBrains Mono', monospace;

  --transition-fast: 0.2s ease;
  --transition-medium: 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  --transition-slow: 0.5s cubic-bezier(0.4, 0, 0.2, 1);
}

* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

body {
  background-color: var(--bg-primary);
  color: var(--color-text-primary);
  font-family: var(--font-body);
  overflow-x: hidden;
  min-height: 100vh;
}

h1, h2, h3, h4, h5, h6 {
  font-family: var(--font-heading);
  letter-spacing: -0.02em;
}

code, pre {
  font-family: var(--font-mono);
}

/* Background Cyber Grid */
.bg-grid {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  z-index: -2;
  background-image: 
    radial-gradient(circle at 50% 50%, rgba(8, 15, 30, 0.5) 0%, var(--bg-primary) 100%),
    linear-gradient(rgba(0, 240, 255, 0.015) 1px, transparent 1px),
    linear-gradient(90deg, rgba(0, 240, 255, 0.015) 1px, transparent 1px);
  background-size: 100% 100%, 40px 40px, 40px 40px;
  background-position: center;
}

/* Ambient Radial Glows */
.bg-glow-cyan {
  position: fixed;
  top: -10%;
  left: -10%;
  width: 50vw;
  height: 50vw;
  background: radial-gradient(circle, rgba(0, 240, 255, 0.07) 0%, transparent 70%);
  z-index: -1;
  pointer-events: none;
  filter: blur(80px);
}

.bg-glow-purple {
  position: fixed;
  bottom: -10%;
  right: -10%;
  width: 60vw;
  height: 60vw;
  background: radial-gradient(circle, rgba(168, 85, 247, 0.05) 0%, transparent 70%);
  z-index: -1;
  pointer-events: none;
  filter: blur(100px);
}

/* Glassmorphism Styles */
.glass-panel {
  background: var(--bg-card);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  border: 1px solid var(--border-glow);
  border-radius: 16px;
  box-shadow: 0 8px 32px 0 rgba(0, 0, 0, 0.4);
  transition: border-color var(--transition-medium), transform var(--transition-medium), background var(--transition-medium);
}

.glass-panel:hover {
  background: var(--bg-card-hover);
  border-color: rgba(0, 240, 255, 0.15);
}

/* Premium Buttons */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  padding: 12px 24px;
  border-radius: 12px;
  font-family: var(--font-heading);
  font-weight: 600;
  font-size: 0.95rem;
  cursor: pointer;
  transition: all var(--transition-fast);
  text-decoration: none;
  border: none;
}

.btn-primary {
  background: linear-gradient(135deg, var(--accent-cyan) 0%, var(--accent-blue) 100%);
  color: #030508;
  box-shadow: 0 4px 20px rgba(0, 240, 255, 0.25);
}

.btn-primary:hover {
  transform: translateY(-2px);
  box-shadow: 0 6px 24px rgba(0, 240, 255, 0.4);
}

.btn-primary:active {
  transform: translateY(0);
}

.btn-secondary {
  background: rgba(255, 255, 255, 0.04);
  color: var(--color-text-primary);
  border: 1px solid rgba(255, 255, 255, 0.08);
}

.btn-secondary:hover {
  background: rgba(255, 255, 255, 0.08);
  border-color: rgba(255, 255, 255, 0.15);
  transform: translateY(-2px);
}

.btn-purple {
  background: linear-gradient(135deg, var(--accent-purple) 0%, #6366f1 100%);
  color: #fff;
  box-shadow: 0 4px 20px rgba(168, 85, 247, 0.25);
}

.btn-purple:hover {
  transform: translateY(-2px);
  box-shadow: 0 6px 24px rgba(168, 85, 247, 0.4);
}

/* Glow Badge */
.glow-badge {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 6px 12px;
  border-radius: 9999px;
  font-size: 0.75rem;
  font-weight: 600;
  letter-spacing: 0.05em;
  text-transform: uppercase;
  background: rgba(0, 240, 255, 0.05);
  color: var(--accent-cyan);
  border: 1px solid rgba(0, 240, 255, 0.2);
  box-shadow: 0 0 12px rgba(0, 240, 255, 0.05);
}

.glow-badge-purple {
  background: rgba(168, 85, 247, 0.05);
  color: var(--accent-purple);
  border: 1px solid rgba(168, 85, 247, 0.2);
}

/* Before/After Slider Container */
.slider-container {
  position: relative;
  width: 100%;
  aspect-ratio: 16/9;
  border-radius: 12px;
  overflow: hidden;
  border: 1px solid rgba(255, 255, 255, 0.1);
  user-select: none;
}

.slider-img {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  object-fit: cover;
  pointer-events: none;
}

.slider-before {
  z-index: 1;
}

.slider-after {
  z-index: 2;
  /* clip-path will be set dynamically via JS react inline styles */
}

.slider-handle {
  position: absolute;
  top: 0;
  bottom: 0;
  width: 4px;
  background-color: var(--accent-cyan);
  z-index: 3;
  cursor: ew-resize;
  box-shadow: 0 0 10px var(--accent-cyan);
}

.slider-handle-button {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  width: 36px;
  height: 36px;
  border-radius: 50%;
  background-color: #030508;
  border: 2px solid var(--accent-cyan);
  display: flex;
  align-items: center;
  justify-content: center;
  box-shadow: 0 0 15px rgba(0, 240, 255, 0.5);
  color: var(--accent-cyan);
}

/* Pulse Animation */
.pulse-indicator {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background-color: var(--accent-green);
  box-shadow: 0 0 8px var(--accent-green);
  animation: pulse 2s infinite;
}

.pulse-indicator-red {
  background-color: var(--accent-pink);
  box-shadow: 0 0 8px var(--accent-pink);
}

@keyframes pulse {
  0% {
    transform: scale(0.95);
    box-shadow: 0 0 0 0 rgba(16, 185, 129, 0.7);
  }
  70% {
    transform: scale(1);
    box-shadow: 0 0 0 6px rgba(16, 185, 129, 0);
  }
  100% {
    transform: scale(0.95);
    box-shadow: 0 0 0 0 rgba(16, 185, 129, 0);
  }
}

/* Pipeline terminal output log styles */
.terminal-window {
  background: #04060a;
  border: 1px solid rgba(255, 255, 255, 0.05);
  border-radius: 8px;
  padding: 16px;
  font-family: var(--font-mono);
  font-size: 0.8rem;
  color: #94a3b8;
  overflow-y: auto;
  max-height: 150px;
}

.terminal-line {
  margin-bottom: 6px;
  line-height: 1.4;
}

.terminal-cyan {
  color: var(--accent-cyan);
}

.terminal-purple {
  color: var(--accent-purple);
}

.terminal-green {
  color: var(--accent-green);
}

/* Responsive grid layout utilities */
.grid-container {
  display: grid;
  gap: 24px;
}

@media (min-width: 768px) {
  .grid-2col {
    grid-template-columns: repeat(2, 1fr);
  }
  .grid-3col {
    grid-template-columns: repeat(3, 1fr);
  }
  .grid-4col {
    grid-template-columns: repeat(4, 1fr);
  }
}

import React, { useState } from 'react';
import { Cpu, Wallet, LogOut, CheckCircle, ShieldAlert, Layers } from 'lucide-react';

