import React, { useState, useEffect, useRef } from 'react';
import { Play, RotateCcw, AlertTriangle, ShieldCheck, Terminal, HelpCircle, Code } from 'lucide-react';

export default function InteractiveDemo() {
  const [prompt, setPrompt] = useState('Pick up the red porcelain mug and place it in the clean tray');
  const [pipelineState, setPipelineState] = useState('idle'); // 'idle' | 'running' | 'success'
  const [logs, setLogs] = useState([]);
  const [activeFrame, setActiveFrame] = useState(0);
  const [sliderPos, setSliderPos] = useState(50);
  const isDragging = useRef(false);
  const sliderRef = useRef(null);

  // Sample prompt templates
  const templates = [
    'Pick up the red porcelain mug and place it in the clean tray',
    'Open the double cabinet drawer and retrieve a metal spatula',
    'Pour 200ml of water from the glass carafe into the mug',
    'Wipe the laboratory surface with a microfiber cloth'
  ];

  // Pipeline simulation logs
  const logSequence = [
    { text: '🟢 [USER_PROMPT] received: ', value: '', color: 'terminal-cyan' },
    { text: '⚡ [isaac-sim] starting 3D physical trajectory rendering...', color: '#94a3b8' },
    { text: '⚡ [isaac-sim] generated joint trajectory (6-DoF, 120 frames, collision-free)', color: '#94a3b8' },
    { text: '🤖 [chutes-ai] invoking serverless RoboTransfer pipeline (Bittensor Subnet 64)...', color: 'terminal-purple' },
    { text: '🤖 [chutes-ai] video diffusion running on Node-A100-8438 (GPU Load: 98.4%)...', color: 'terminal-purple' },
    { text: '🛡️ [sentient-oml] signing model fingerprint and verifying physical consistency...', color: 'terminal-purple' },
    { text: '🛡️ [sentient-oml] registered OML fingerprint: oml_model_0x8f2a83c66fbcee1c...', color: 'terminal-green' },
    { text: '🎉 [pipeline] successfully generated 120 high-fidelity frames with label vectors!', color: 'terminal-green' }
  ];

  // Run the mock pipeline
  const runPipeline = () => {
    if (pipelineState === 'running') return;
    setPipelineState('running');
    setLogs([]);
    setActiveFrame(0);

    let logIndex = 0;
    const interval = setInterval(() => {
      if (logIndex < logSequence.length) {
        const currentLog = logSequence[logIndex];
        const textToPrint = currentLog.text + (logIndex === 0 ? `"${prompt}"` : (currentLog.value || ''));
        setLogs(prev => [...prev, { text: textToPrint, color: currentLog.color }]);
        logIndex++;
      } else {
        clearInterval(interval);
        setPipelineState('success');
      }
    }, 850);
  };

  // Loop frames when state is idle or success
  useEffect(() => {
    let frameTimer;
    if (pipelineState === 'idle' || pipelineState === 'success') {
      frameTimer = setInterval(() => {
        setActiveFrame(prev => (prev + 1) % 120);
      }, 50);
    }
    return () => clearInterval(frameTimer);
  }, [pipelineState]);

  // Handle slider drag
  const handleMove = (clientX) => {
    if (!sliderRef.current) return;
    const rect = sliderRef.current.getBoundingClientRect();
    const x = clientX - rect.left;
    let pos = (x / rect.width) * 100;
    if (pos < 0) pos = 0;
    if (pos > 100) pos = 100;
    setSliderPos(pos);
  };

  const handleTouchMove = (e) => {
    if (!isDragging.current) return;
    handleMove(e.touches[0].clientX);
  };

  const handleMouseMove = (e) => {
    if (!isDragging.current) return;
    handleMove(e.clientX);
  };

  useEffect(() => {
    const handleMouseUp = () => {
      isDragging.current = false;
    };
    window.addEventListener('mouseup', handleMouseUp);
    window.addEventListener('touchend', handleMouseUp);
    return () => {
      window.removeEventListener('mouseup', handleMouseUp);
      window.removeEventListener('touchend', handleMouseUp);
    };
  }, []);

  // Compute animated angles for SVG drawing based on activeFrame
  const progressRad = (activeFrame / 119) * Math.PI * 2;
  const shoulderAngle = 40 + Math.sin(progressRad) * 25;
  const elbowAngle = -60 + Math.cos(progressRad) * 35;
  const gripperClose = activeFrame > 50 && activeFrame < 100;
  const cupX = activeFrame > 60 && activeFrame < 105 ? 180 + Math.sin((activeFrame - 60)/45 * Math.PI) * 40 : (activeFrame >= 105 ? 220 : 180);
  const cupY = activeFrame > 60 && activeFrame < 105 ? 240 - Math.sin((activeFrame - 60)/45 * Math.PI) * 50 : 240;

  // Mock Joint Data updated in real-time
  const activeJoints = [
    (shoulderAngle).toFixed(1),
    (elbowAngle).toFixed(1),
    (gripperClose ? 15.0 : 45.0).toFixed(1),
    '0.0',
    '90.0',
    (Math.sin(progressRad) * 10).toFixed(1)
  ];

  const endEffectorX = (0.35 + Math.sin(progressRad) * 0.15).toFixed(3);
  const endEffectorY = (0.02 + Math.cos(progressRad) * 0.05).toFixed(3);
  const endEffectorZ = (0.28 + Math.sin(progressRad) * 0.1).toFixed(3);

  return (
    <section id="sandbox" style={{
      maxWidth: '1200px',
      margin: '80px auto 0 auto',
      padding: '0 24px'
    }}>
      <div style={{ textAlign: 'center', marginBottom: '40px' }}>
        <h2 style={{ fontSize: '2.2rem', fontWeight: 800, marginBottom: '12px' }}>
          Sim-to-Real Sandbox
        </h2>
        <p style={{ color: 'var(--color-text-secondary)', maxWidth: '600px', margin: '0 auto' }}>
          Type a robot task or choose a template below. Watch how Chutes.ai generates a synthetic 3D physics render and automatically applies RoboTransfer.
        </p>
      </div>

      <div className="grid-container grid-2col">
        {/* Left: Configuration & Console Logs */}
        <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
          {/* Prompt Entry */}
          <div className="glass-panel" style={{ padding: '24px', border: '1px solid rgba(255, 255, 255, 0.05)' }}>
            <h3 style={{ fontSize: '1.1rem', marginBottom: '14px', display: 'flex', alignItems: 'center', gap: '8px', color: '#fff' }}>
              <Code size={18} color="var(--accent-cyan)" />
              Robotic Instruction
            </h3>

            <div style={{ position: 'relative', marginBottom: '16px' }}>
