import React, { useState, useEffect } from 'react';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import InteractiveDemo from './components/InteractiveDemo';
import StatsTelemetry from './components/StatsTelemetry';
import ArchitectureMap from './components/ArchitectureMap';
import Footer from './components/Footer';
import { ShieldAlert, Globe } from 'lucide-react';

function App() {
  const [walletAddress, setWalletAddress] = useState('');
  const [walletType, setWalletType] = useState('');
  const [isRestricted, setIsRestricted] = useState(null); // null (checking), true, false
  const [userCountry, setUserCountry] = useState('');

  useEffect(() => {
    // Restricted countries list:
    // KR: South Korea (Domestic Crypto Regulations)
    // US: United States (SEC Securities laws)
    // CN: China (Cryptocurrency transactions banned)
    // KP, IR, SY, CU: Sanctioned regions
    const restrictedCodes = ['KR', 'US', 'CN', 'KP', 'IR', 'SY', 'CU'];

    const checkIPAddress = async () => {
      try {
        const res = await fetch('https://ipapi.co/json/');
        const data = await res.json();
        if (data && data.country_code) {
          setUserCountry(data.country_name || data.country_code);
          if (restrictedCodes.includes(data.country_code.toUpperCase())) {
            setIsRestricted(true);
          } else {
            setIsRestricted(false);
          }
        } else {
          // Fallback if country code is missing
          setIsRestricted(false);
        }
      } catch (err) {
        console.error("Geofencing verification error:", err);
        // If external API is blocked/down, default to false (or true for maximum caution)
        setIsRestricted(false);
      }
    };

    checkIPAddress();
  }, []);

  // 1. Loading screen while checking region
  if (isRestricted === null) {
    return (
      <div style={{
        height: '100vh',
        backgroundColor: '#030508',
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        color: '#94a3b8',
        fontFamily: 'var(--font-body)'
      }}>
        <div style={{
          width: '30px',
          height: '30px',
          borderRadius: '50%',
          border: '2px solid rgba(0, 240, 255, 0.1)',
          borderTopColor: 'var(--accent-cyan)',
          animation: 'spin 1s linear infinite',
          marginBottom: '16px'
        }} />
        <span style={{ fontSize: '0.9rem', letterSpacing: '0.05em' }}>VERIFYING SECURE REGION...</span>
        <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
      </div>
    );
  }

  // 2. Geofenced Restricted Screen
  if (isRestricted === true) {
    return (
      <div style={{
        height: '100vh',
        backgroundColor: '#030508',
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        padding: '24px',
        textAlign: 'center',
        fontFamily: 'var(--font-body)'
      }}>
        {/* Background Cyber Grid */}
        <div className="bg-grid" />

        <div className="glass-panel" style={{
          maxWidth: '550px',
          padding: '40px',
          border: '1px solid rgba(244, 63, 94, 0.3)',
          boxShadow: '0 0 30px rgba(244, 63, 94, 0.1)',
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center'
        }}>
          <div style={{
            width: '64px',
            height: '64px',
            borderRadius: '50%',
            backgroundColor: 'rgba(244, 63, 94, 0.1)',
            border: '2px solid var(--accent-pink)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            marginBottom: '24px',
            color: 'var(--accent-pink)',
            boxShadow: '0 0 20px rgba(244, 63, 94, 0.2)'
          }}>
            <ShieldAlert size={32} />
          </div>

          <h1 style={{
            fontSize: '1.8rem',
            fontWeight: 800,
            color: '#fff',
            marginBottom: '16px',
            fontFamily: 'var(--font-heading)'
          }}>
            Access Restricted
          </h1>

          <p style={{
            color: 'var(--color-text-secondary)',
            fontSize: '0.95rem',
            lineHeight: 1.6,
            marginBottom: '20px'
          }}>
            Due to local compliance rules, virtual asset regulations, and securities laws, access to the <strong>surfrobot</strong> platform is prohibited from your current region ({userCountry}).
          </p>

          <div style={{
            background: 'rgba(255, 255, 255, 0.02)',
            border: '1px solid rgba(255, 255, 255, 0.05)',
            borderRadius: '8px',
            padding: '12px 16px',
            fontSize: '0.8rem',
            color: 'var(--color-text-muted)',
            display: 'flex',
            alignItems: 'center',
            gap: '8px',
            width: '100%',
            justifyContent: 'center'
          }}>
            <Globe size={14} />
            <span>Restricted Regions: KR, US, CN, KP, IR, SY, CU</span>
          </div>
        </div>
      </div>
    );
  }

  // 3. Allowed Screen (Standard App)
  return (
    <>
      {/* Premium Background Visuals */}
      <div className="bg-grid" />
      <div className="bg-glow-cyan" />
      <div className="bg-glow-purple" />

      {/* Main Header / Navigation */}
      <Navbar 
        walletAddress={walletAddress} 
        setWalletAddress={setWalletAddress} 
        walletType={walletType} 
        setWalletType={setWalletType} 
      />

      {/* Landing Page Content */}
      <main style={{ paddingBottom: '60px' }}>
        <Hero />
        <InteractiveDemo />
        <StatsTelemetry />
        <ArchitectureMap />
      </main>

      {/* Footer Details */}
      <Footer />
    </>
  );
}

export default App;

